  1	import * as React from 'react';
  2	import { arbiterText } from '@odf/core/constants';
  3	import { AdvancedSubscription } from '@odf/shared/badges/advanced-subscription';
  4	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
