  6	  Select,
  7	  SelectOption,
  8	  SelectList,
  9	  SelectProps,
 10	  MenuToggle,
 11	  MenuToggleElement,
 12	  FormGroup,
 13	  Alert,
 14	  Checkbox,
 15	  TextContent,
 16	  TextVariants,
 17	  Text,
 18	  FormHelperText,
 19	  HelperTextItem,
 20	  HelperText as PfHelperText,
 21	} from '@patternfly/react-core';
 22	import { WizardState } from '../../reducer';
 23	import './capacity-and-nodes.scss';
 24	
 25	const HelperText: React.FC<{ enableArbiter: boolean }> = ({
 26	  enableArbiter,
 27	}) => {
 28	  const { t } = useCustomTranslation();
 29	  return (
 30	    <>
 31	      <TextContent>
 32	        <Text component={TextVariants.small}>
 33	          {t(
 34	            'To support high availability when two data centers can be used, enable arbiter to get a valid quorum between the two data centers.'
 35	          )}
 36	        </Text>
 37	      </TextContent>
 38	      {enableArbiter && (
 39	        <Alert
 40	          title={t('Arbiter minimum requirements')}
 41	          variant="info"
 42	          isInline
 43	        >
 44	          {arbiterText(t)}
 45	        </Alert>
 46	      )}
 47	    </>
 48	  );
 49	};
 50	
 51	const EnableArbiterLabel: React.FC = () => {
 52	  const { t } = useCustomTranslation();
 53	
 54	  return (
 55	    <div className="ocs-enable-arbiter-label">
 56	      <span className="ocs-enable-arbiter-label__title--padding">
 57	        {t('Enable arbiter')}
 58	      </span>
 59	      <AdvancedSubscription />
 60	    </div>
 61	  );
 62	};
 63	
 64	export const StretchCluster: React.FC<StretchClusterProps> = ({
 65	  onSelect,
 66	  onChecked,
 67	  zones,
 68	  enableArbiter,
 69	  arbiterLocation,
 70	}) => {
 71	  const { t } = useCustomTranslation();
 72	  const [isOpen, setIsOpen] = React.useState(false);
 73	
 74	  const handleSelection: SelectProps['onSelect'] = (e, selection) => {
 75	    onSelect(e, selection);
 76	    setIsOpen(false);
 77	  };
 78	
 79	  const arbiterLocationToggle = (toggleRef: React.Ref<MenuToggleElement>) => (
 80	    <MenuToggle
 81	      ref={toggleRef}
 82	      onClick={() => setIsOpen((prev) => !prev)}
 83	      isExpanded={isOpen}
 84	      isFullWidth
 85	    >
 86	      {arbiterLocation || t('Select an arbiter zone')}
 87	    </MenuToggle>
 88	  );
 89	
 90	  return (
 91	    <>
 92	      <TextContent>
 93	        <Text component={TextVariants.h3}>{t('Stretch Cluster')}</Text>
 94	      </TextContent>
 95	      <Checkbox
 96	        aria-label={t('Enable arbiter')}
 97	        id="stretch-cluster"
 98	        isChecked={enableArbiter}
 99	        data-checked-state={enableArbiter}
100	        label={<EnableArbiterLabel />}
101	        description={<HelperText enableArbiter={enableArbiter} />}
102	        onChange={(_event, hasChecked: boolean) => {
103	          if (!hasChecked) onSelect(null, '');
104	          onChecked(hasChecked);
105	        }}
106	        body={
107	          enableArbiter && (
108	            <FormGroup
109	              label={t('Arbiter zone')}
110	              fieldId="arbiter-zone-selection"
111	            >
112	              <Select
113	                id="arbiter-zone-selection"
114	                isOpen={isOpen}
115	                selected={arbiterLocation}
116	                onSelect={handleSelection}
117	                onOpenChange={setIsOpen}
118	                toggle={arbiterLocationToggle}
119	                aria-label={t('Arbiter zone selection')}
120	              >
121	                <SelectList>
122	                  {zones.map((zone) => (
123	                    <SelectOption key={zone} value={zone}>
124	                      {zone}
125	                    </SelectOption>
126	                  ))}
127	                </SelectList>
128	              </Select>
129	              <FormHelperText>
130	                <PfHelperText>
131	                  <HelperTextItem>
132	                    {t(
133	                      'An arbiter node will be automatically selected from this zone'
134	                    )}
135	                  </HelperTextItem>
136	                </PfHelperText>
137	              </FormHelperText>
138	            </FormGroup>
139	          )
140	        }
141	      />
142	    </>
143	  );
144	};
145	
146	type StretchClusterProps = {
147	  onSelect: SelectProps['onSelect'];
148	  onChecked: (isChecked: boolean) => void;
149	  arbiterLocation: WizardState['capacityAndNodes']['arbiterLocation'];
150	  enableArbiter: WizardState['capacityAndNodes']['enableArbiter'];
151	  zones: string[];
152	};

